import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { GangStatusParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/GangStatusParser';

export class GangStatusEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, GangStatusParser);
        console.log('[🏴‍☠️] GangStatusEvent initialized!');
    }

    public getParser(): GangStatusParser {
        return this.parser as GangStatusParser;
    }
}
